import json
import random
import ast

# ================= 配置区域 =================
FILE_PATH = "/mnt/shared-storage-user/yangpenghui1/data/gad/gpt5-chat/lmsys_gpt5_chat_filtered_train.jsonl"
SAMPLE_NUM = 1
# ===========================================

def parse_line(line: str):
    line = line.strip()
    if not line:
        return None

    # 1) 标准 JSON
    try:
        return json.loads(line)
    except json.JSONDecodeError:
        pass

    # 2) Python 字面量（处理单引号等）
    try:
        return ast.literal_eval(line)
    except Exception:
        return None

def random_sample_jsonl(file_path: str, k: int, encoding="utf-8"):
    """
    从 JSONL 中随机抽取 k 条（reservoir sampling）。
    返回：samples(list), processed_lines(int), valid_lines(int)
    """
    reservoir = []
    processed = 0   # 总行数（含空行/坏行）
    valid = 0       # 解析成功的行数

    with open(file_path, "r", encoding=encoding) as f:
        for line in f:
            processed += 1

            if processed % 100000 == 0:
                print(f"已扫描 {processed} 行...", end="\r")

            obj = parse_line(line)
            if obj is None:
                continue

            # 只对“有效行”做水塘抽样，保证随机性基于有效样本
            if valid < k:
                reservoir.append(obj)
            else:
                r = random.randint(0, valid)
                if r < k:
                    reservoir[r] = obj
            valid += 1

    return reservoir, processed, valid

if __name__ == "__main__":
    print(f"正在读取文件: {FILE_PATH}")
    print(f"目标抽取数量: {SAMPLE_NUM}")
    print("-" * 50)

    try:
        samples, processed, valid = random_sample_jsonl(FILE_PATH, SAMPLE_NUM, encoding="utf-8")
    except UnicodeDecodeError:
        # 如果文件不是 utf-8（例如有乱码），尝试用 utf-8-sig 或忽略错误
        samples, processed, valid = random_sample_jsonl(FILE_PATH, SAMPLE_NUM, encoding="utf-8-sig")
    except FileNotFoundError:
        print(f"错误: 找不到文件 {FILE_PATH}")
        raise

    print(f"\n扫描完成：总行数 {processed}，有效JSON行数 {valid}。")
    print("=" * 50)

    if not samples:
        print("未抽到样本：文件可能为空，或所有行都无法解析为JSON/字典。")
    else:
        for idx, item in enumerate(samples, 1):
            print(f"【样本 {idx}】")
            print(json.dumps(item, indent=2, ensure_ascii=False))
            print("-" * 30)
